// Command dsqgen renders TPC-DS query streams for a target SQL dialect, drawing
// valid, scale-correct parameter values with a seeded RNG (it does not
// reproduce the C dsqgen's exact value stream). Output is a single .sql file per
// stream with one `--= query_N` marker per statement, the format the stroppy
// workloads consume via parse_sql.
package main

import (
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/stroppy-io/stroppy/third_party/gotpcds/dsqgen"
)

func main() {
	dialectName := flag.String("dialect", "postgres", "target dialect: postgres|mysql")
	scale := flag.Float64("scale", 1, "scale factor for rowcount-dependent ranges")
	seed := flag.Int64("seed", 19620718, "base RNG seed")
	streams := flag.Int("streams", 1, "number of query streams to generate")
	outDir := flag.String("out", ".", "output directory")
	flag.Parse()

	dialect, ok := dsqgen.DialectByName(*dialectName)
	if !ok {
		fmt.Fprintf(os.Stderr, "unknown dialect %q\n", *dialectName)
		os.Exit(2)
	}

	if err := os.MkdirAll(*outDir, 0o755); err != nil {
		fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}

	for s := 0; s < *streams; s++ {
		res, err := dsqgen.Generate(dialect, *scale, *seed+int64(s)*1_000_003, s)
		if err != nil {
			fmt.Fprintln(os.Stderr, err)
			os.Exit(1)
		}
		var b strings.Builder
		fmt.Fprintf(&b, "-- TPC-DS query stream %d for %s (scale %g, seed %d). Generated by dsqgen.\n",
			s, dialect.Name, *scale, *seed)
		for _, q := range res.Queries {
			b.WriteString(markStatements(q))
		}
		path := filepath.Join(*outDir, fmt.Sprintf("%s_stream_%d.sql", dialect.Name, s))
		if err := os.WriteFile(path, []byte(b.String()), 0o644); err != nil {
			fmt.Fprintln(os.Stderr, err)
			os.Exit(1)
		}
		fmt.Printf("wrote %s (%d queries, %d skipped)\n", path, len(res.Queries), len(res.Skipped))
		for _, sk := range res.Skipped {
			fmt.Printf("  skipped %s\n", sk)
		}
	}
}

// markStatements splits a query's body on ';' and emits one `--= name[_b]`
// section per statement (queries 14/23/24/39 are two-part).
func markStatements(q dsqgen.Query) string {
	var out strings.Builder
	parts := strings.Split(q.SQL, ";")
	idx := 0
	suffix := []string{"_a", "_b", "_c"}
	var stmts []string
	for _, p := range parts {
		if strings.TrimSpace(p) != "" {
			stmts = append(stmts, strings.TrimSpace(p))
		}
	}
	for _, st := range stmts {
		name := q.Name
		if len(stmts) > 1 {
			name += suffix[idx]
		}
		fmt.Fprintf(&out, "--= %s\n%s\n;\n\n", name, st)
		idx++
	}
	return out.String()
}
